sys_script_include.script:
var AutoIncreaseDayUtils = Class.create();
AutoIncreaseDayUtils.prototype = {
    initialize: function() {},

    /**
     * Calculate remaining days between current date and BID Recruit start date,
     * then update the YTD field for all BID Presales records.
     * Leverage GlideDateTime and GlideRecord for date calculation and bulk update.
     */
    updateRemainingDays: function() {
        var grBIDPresales = new GlideRecord("x_1763182_talent_0_bid_presales");
        grBIDPresales.query();

        var now = new GlideDateTime();

        while (grBIDPresales.next()) {

            var startDate = grBIDPresales.u_bid_recruit_id.u_start_date;

            if (!startDay.nil()) {
                var start = new GlideDateTime(startDate);
                var diff = GlideDateTime.subtract(start, now);

                grBIDPresales.u_ytd = diff.getDayPart();

                grBIDPresales.update();
            }
        }
    },

    type: 'AutoIncreaseDayUtils'
};
